import{_ as e,o as t,c as s,a3 as r}from"./chunks/framework.DXXx-gl1.js";const c=JSON.parse('{"title":"调试技巧","description":"","frontmatter":{},"headers":[],"relativePath":"zh/PortingGuides/Debug.md","filePath":"zh/PortingGuides/Debug.md","lastUpdated":1771002312000}'),o={name:"zh/PortingGuides/Debug.md"};function n(i,a,_,l,p,u){return t(),s("div",null,[...a[0]||(a[0]=[r(`<h1 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h1><h2 id="打开日志输出" tabindex="-1">打开日志输出 <a class="header-anchor" href="#打开日志输出" aria-label="Permalink to &quot;打开日志输出&quot;">​</a></h2><p>我们的UEFI目前提供4种获取UEFI日志的方式。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  USE_SCREEN_FOR_SERIAL_OUTPUT    = 0</span></span>
<span class="line"><span>  USE_UART_GENI_FOR_SERIAL_OUTPUT = 0</span></span>
<span class="line"><span>  USE_UART_DM_FOR_SERIAL_OUTPUT   = 0</span></span>
<span class="line"><span>  USE_MEMORY_FOR_SERIAL_OUTPUT    = 0</span></span></code></pre></div><p>同时只能启用其中一种。</p><h3 id="use-screen-for-serial-output" tabindex="-1">USE_SCREEN_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-screen-for-serial-output" aria-label="Permalink to &quot;USE_SCREEN_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>设置为 <strong>1</strong> 以通过屏幕启用串行输出。日志将直接打印到屏幕上。这种方式对于没有UART的设备非常<strong>有用</strong>。</p><h3 id="use-uart-geni-for-serial-output" tabindex="-1">USE_UART_GENI_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-uart-geni-for-serial-output" aria-label="Permalink to &quot;USE_UART_GENI_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>设置为 <strong>1</strong> 以通过真实串行端口启用串行输出。日志将打印到 geni uart 地址 <code>gAndromedaPkgTokenSpaceGuid.PcdUartSerialBase</code>，该地址在 <em>Silicon/QC/XXX/QcomPkg/QcomPkg.dsc.inc</em> 中定义。</p><h3 id="use-uart-dm-for-serial-output" tabindex="-1">USE_UART_DM_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-uart-dm-for-serial-output" aria-label="Permalink to &quot;USE_UART_DM_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>与 <strong>USE_UART_GENI_FOR_SERIAL_OUTPUT</strong> 类似。它用于较旧的Qualcomm平台，如msm8996。</p><h3 id="use-memory-for-serial-output" tabindex="-1">USE_MEMORY_FOR_SERIAL_OUTPUT <a class="header-anchor" href="#use-memory-for-serial-output" aria-label="Permalink to &quot;USE_MEMORY_FOR_SERIAL_OUTPUT&quot;">​</a></h3><p>设置为 <strong>1</strong> 以将日志打印到pstore内存。当您的设备上有JTAG或启用EUD时，这很有用。输出区域在您的设备的 <em>Library/PlatformMemoryMapLib/PlatformMemoryMapLib.c</em> 中定义。该区域必须命名为 <em>PStore</em>，如下所示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;PStore&quot;, &lt;StartAddress&gt;, &lt;Size&gt;, AddMem, MEM_RES, SYS_MEM_CAP, Reserv, WRITE_THROUGH_XN},</span></span></code></pre></div>`,14)])])}const U=e(o,[["render",n]]);export{c as __pageData,U as default};
